import { Injectable, inject } from '@angular/core'
import { HttpClient } from '@angular/common/http'
import { API_BASE_URL, AUTH_TOKEN_KEY } from '../../services/api.config'
import { BehaviorSubject, firstValueFrom } from 'rxjs'
import { Auth, signInAnonymously, signInWithPopup, GoogleAuthProvider, signInWithEmailAndPassword, signOut, User as FirebaseUser, idToken } from '@angular/fire/auth'

export interface User {
  id: string
  email?: string
  roles?: string[]
  permissions?: string[]
  [key: string]: unknown
}

export interface AuthExchangeResponse {
  token: string
  user: {
    id: string
    roles: string[]
    permissions: string[]
  }
}

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly _isAuthenticated = new BehaviorSubject<boolean>(false)
  private readonly _user = new BehaviorSubject<User | null>(null)

  readonly isAuthenticated$ = this._isAuthenticated.asObservable()
  readonly user$ = this._user.asObservable()

  get currentUserValue(): User | null {
    return this._user.value
  }

  private auth: Auth = inject(Auth)
  private http = inject(HttpClient)

  // Expose firebase auth state for components that need to wait for it (like Firestore listeners)
  readonly firebaseAuthReady$ = new BehaviorSubject<boolean>(false)

  constructor() {
    this.initializeAuth()
  }

  private initializeAuth(): void {
    // Listen to Firebase Auth State
    this.auth.onAuthStateChanged(async (firebaseUser) => {
      console.log('[AuthService] onAuthStateChanged:', firebaseUser?.uid)

      if (firebaseUser) {
        // User is signed in (anonymous or real)
        this.firebaseAuthReady$.next(true)

        if (!firebaseUser.isAnonymous) {
          // It's a real user, try to exchange token for Janus session
          await this.handleRealUserLogin(firebaseUser)
        } else {
          // If anonymous, we might still want to be "authenticated" as guest or admin-bypass if needed
          // For now, keeping the "Auto-login as Admin" bypass if no real user is present?
          // The original code forced admin. Let's keep the bypass behavior strictly if requested, 
          // but ideally we want real login. 
          // Logic: If NO token in localStorage, maybe default to admin for dev?
          // User said "Firebase as SSOT". So let's rely on Firebase.
          // If anonymous, we are NOT authenticated in the app sense (unless guest).
        }
      } else {
        // Signed out
        this._isAuthenticated.next(false)
        this._user.next(null)

        // Ensure anonymous session for Firestore if needed? 
        // Original code did signInAnonymously. We can keep that for "public" access if desired.
        signInAnonymously(this.auth).catch(err => console.error('Anon auth failed', err));
      }
    })

    // Check if we have a Janus token already? 
    const token = localStorage.getItem(AUTH_TOKEN_KEY)
    if (token) {
      // Validate token or just assume true for now?
      // Ideally we validate. For now, let's just set true to avoid flicker if valid.
      // But if Firebase triggers "null" user, we might log out.
      // Let's rely on Firebase auth state mainly.
    }
  }

  async loginWithPassword(email: string, password: string, remember: boolean): Promise<boolean> {
    console.log('[AuthService] loginWithPassword:start', { emailMasked: !!email })
    try {
      const cred = await signInWithEmailAndPassword(this.auth, email, password)
      // onAuthStateChanged will handle the rest
      return true
    } catch (err) {
      console.error('[AuthService] loginWithPassword error', err)
      return false
    }
  }

  async loginWithProvider(provider: 'google' | 'github'): Promise<boolean> {
    console.log('[AuthService] loginWithProvider:start', { provider })
    try {
      if (provider === 'google') {
        await signInWithPopup(this.auth, new GoogleAuthProvider())
        return true
      }
      // Github not yet implemented in this refactor, falling back or error
      console.warn('Github auth not implemented in Firebase refactor yet')
      return false
    } catch (err) {
      console.error('[AuthService] loginWithProvider error', err)
      return false
    }
  }

  // Helper to exchange Firebase ID Token for Janus Token
  private async handleRealUserLogin(firebaseUser: FirebaseUser) {
    try {
      const token = await firebaseUser.getIdToken()
      // Reuse existing endpoint for now. Ideally should be /v1/auth/firebase/exchange
      const out = await firstValueFrom(this.http.post<AuthExchangeResponse>(`${API_BASE_URL}/v1/auth/supabase/exchange`, { token }))

      const janus = String(out?.token || '')
      if (janus) {
        localStorage.setItem(AUTH_TOKEN_KEY, janus)

        this._isAuthenticated.next(true)
        this._user.next({
          id: out.user?.id || firebaseUser.uid,
          email: firebaseUser.email || '',
          roles: out.user?.roles || ['user'],
          permissions: out.user?.permissions || ['read']
        })
        console.log('[AuthService] Janus Exchange Success')
      }
    } catch (err) {
      console.error('[AuthService] Janus Exchange Failed', err)
      this.logout()
    }
  }

  async logout(): Promise<void> {
    console.log('[AuthService] logout')
    localStorage.removeItem(AUTH_TOKEN_KEY)
    this._isAuthenticated.next(false)
    this._user.next(null)
    await signOut(this.auth)
  }
}

/**
 * Guards de autenticação e autorização para rotas Angular
 * Implementa proteção de rotas baseada em autenticação e permissões
 */

import { Injectable, inject } from '@angular/core';
import { CanActivate, CanActivateChild, CanLoad, Router, ActivatedRouteSnapshot, RouterStateSnapshot, Route, UrlSegment } from '@angular/router';
import { Observable, map, take, tap } from 'rxjs';
import { AuthService } from '../auth/auth.service';
import { NotificationService } from '../notifications/notification.service';

@Injectable({
  providedIn: 'root'
})
export class AuthGuard implements CanActivate, CanActivateChild, CanLoad {
  private authService = inject(AuthService);
  private router = inject(Router);
  private notificationService = inject(NotificationService);

  canActivate(
    route: ActivatedRouteSnapshot,
    state: RouterStateSnapshot
  ): Observable<boolean> | Promise<boolean> | boolean {
    return this.checkAuth(route, state);
  }

  canActivateChild(
    route: ActivatedRouteSnapshot,
    state: RouterStateSnapshot
  ): Observable<boolean> | Promise<boolean> | boolean {
    return this.canActivate(route, state);
  }

  canLoad(
    route: Route,
    segments: UrlSegment[]
  ): Observable<boolean> | Promise<boolean> | boolean {
    return this.checkAuthForLoad();
  }

  private checkAuth(route?: ActivatedRouteSnapshot, state?: RouterStateSnapshot): Observable<boolean> {
    return this.authService.isAuthenticated$.pipe(
      take(1),
      map(isAuthenticated => {
        if (isAuthenticated) {
          return true;
        }

        // Redirecionar para login com URL de retorno
        const returnUrl = state?.url || route?.url?.join('/') || '/';
        this.router.navigate(['/auth/login'], { 
          queryParams: { returnUrl },
          replaceUrl: true
        });

        this.notificationService.notifyWarning('Acesso negado', 'Por favor, faça login para acessar esta página');
        return false;
      })
    );
  }

  private checkAuthForLoad(): Observable<boolean> {
    return this.authService.isAuthenticated$.pipe(
      take(1),
      map(isAuthenticated => {
        if (!isAuthenticated) {
          this.notificationService.notifyWarning('Acesso negado', 'Por favor, faça login para acessar este módulo');
        }
        return isAuthenticated;
      })
    );
  }
}

@Injectable({
  providedIn: 'root'
})
export class RoleGuard implements CanActivate {
  private authService = inject(AuthService);
  private router = inject(Router);
  private notificationService = inject(NotificationService);

  canActivate(route: ActivatedRouteSnapshot): Observable<boolean> | Promise<boolean> | boolean {
    const requiredRoles = route.data['roles'] as string[];

    if (!requiredRoles || requiredRoles.length === 0) {
      return true;
    }

    return this.authService.user$.pipe(
      take(1),
      map(user => {
        if (!user) {
          this.router.navigate(['/auth/login']);
          return false;
        }

        const hasRole = requiredRoles.some(role => user.roles?.includes(role) || false);

        if (!hasRole) {
          this.notificationService.notifyError('Acesso negado', 'Você não tem permissão para acessar esta página');
          this.router.navigate(['/dashboard']);
          return false;
        }

        return true;
      })
    );
  }
}

@Injectable({
  providedIn: 'root'
})
export class PermissionGuard implements CanActivate {
  private authService = inject(AuthService);
  private router = inject(Router);
  private notificationService = inject(NotificationService);

  canActivate(route: ActivatedRouteSnapshot): Observable<boolean> | Promise<boolean> | boolean {
    const requiredPermissions = route.data['permissions'] as string[];

    if (!requiredPermissions || requiredPermissions.length === 0) {
      return true;
    }

    return this.authService.user$.pipe(
      take(1),
      map(user => {
        if (!user) {
          this.router.navigate(['/auth/login']);
          return false;
        }

        const hasPermission = requiredPermissions.every(permission => 
          user.permissions?.includes(permission) || false
        );

        if (!hasPermission) {
          this.notificationService.notifyError('Acesso negado', 'Você não tem as permissões necessárias para acessar esta página');
          this.router.navigate(['/dashboard']);
          return false;
        }

        return true;
      })
    );
  }
}

@Injectable({
  providedIn: 'root'
})
export class NoAuthGuard implements CanActivate {
  private authService = inject(AuthService);
  private router = inject(Router);

  canActivate(): Observable<boolean> | Promise<boolean> | boolean {
    return this.authService.isAuthenticated$.pipe(
      take(1),
      map(isAuthenticated => {
        if (!isAuthenticated) {
          return true;
        }

        // Se já está autenticado, redirecionar para dashboard
        this.router.navigate(['/dashboard']);
        return false;
      })
    );
  }
}

/**
 * Guard para verificar se o sistema está pronto
 * Útil para verificar configurações iniciais, conexões, etc.
 */
@Injectable({
  providedIn: 'root'
})
export class SystemReadyGuard implements CanActivate {
  private authService = inject(AuthService);
  private router = inject(Router);
  private notificationService = inject(NotificationService);

  canActivate(): Observable<boolean> | Promise<boolean> | boolean {
    // Verificar se o sistema está configurado e pronto
    return this.checkSystemReadiness().pipe(
      map(isReady => {
        if (!isReady) {
          this.notificationService.notifyWarning('Sistema não pronto', 'O sistema ainda está sendo configurado. Por favor, aguarde.');
          this.router.navigate(['/setup']);
          return false;
        }
        return true;
      })
    );
  }

  private checkSystemReadiness(): Observable<boolean> {
    // Implementar lógica de verificação do sistema
    // Por exemplo: verificar configurações, conexões, etc.
    return this.authService.isAuthenticated$;
  }
}

import { HttpInterceptorFn } from '@angular/common/http';
import { AUTH_TOKEN_KEY } from '../../services/api.config';
import { decodeTokenUserId } from '../../services/auth.utils';

/**
 * Opcionalmente anexa Authorization: Bearer <token> quando disponível.
 * - Lê token de localStorage pela chave configurável (AUTH_TOKEN_KEY)
 * - Não sobrescreve cabeçalhos Authorization existentes
 * - Não impõe credenciais; requests anônimas continuam funcionando
 */
export const authInterceptor: HttpInterceptorFn = (req, next) => {
  try {
    const token = localStorage.getItem(AUTH_TOKEN_KEY);
    const setHeaders: Record<string, string> = {};

    if (!req.headers.has('Authorization') && token) {
      setHeaders['Authorization'] = `Bearer ${token}`;
    }

    if (!req.headers.has('X-User-Id') && token) {
      const uid = decodeTokenUserId(token);
      if (uid !== null) {
        setHeaders['X-User-Id'] = String(uid);
      }
    }

    // Debug: Log requests to chat history
    if (req.url.includes('/api/v1/chat/') && req.url.includes('/history')) {
      console.log('[AuthInterceptor] Chat history request:', {
        url: req.url,
        hasAuthHeader: req.headers.has('Authorization'),
        hasUserIdHeader: req.headers.has('X-User-Id'),
        headers: req.headers.keys(),
        method: req.method
      });
    }

    if (Object.keys(setHeaders).length > 0) {
      const cloned = req.clone({ setHeaders });
      return next(cloned);
    }

    return next(req);
  } catch {
    return next(req);
  }
};

/**
 * Interceptors HTTP para tratamento global de erros e loading
 * Implementa tratamento centralizado de erros e estados de carregamento
 */

import { Injectable, inject } from '@angular/core';
import { HttpInterceptor, HttpRequest, HttpHandler, HttpEvent, HttpErrorResponse, HttpResponse } from '@angular/common/http';
import { Observable, throwError, finalize, catchError, tap, timeout } from 'rxjs';
import { LoadingStateService } from '../services/loading-state.service';
import { NotificationService } from '../notifications/notification.service';

import { Router } from '@angular/router';

@Injectable()
export class LoadingInterceptor implements HttpInterceptor {
  private loadingStateService = inject(LoadingStateService);
  private activeRequests = 0;

  intercept(req: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
    // Não mostrar loading para requisições específicas
    if (this.shouldSkipLoading(req)) {
      return next.handle(req);
    }

    this.activeRequests++;
    if (this.activeRequests === 1) {
      this.loadingStateService.startLoading('http-request', 'Carregando...');
    }

    return next.handle(req).pipe(
      finalize(() => {
        this.activeRequests--;
        if (this.activeRequests === 0) {
          this.loadingStateService.stopLoading('http-request');
        }
      })
    );
  }

  private shouldSkipLoading(req: HttpRequest<any>): boolean {
    // Skip loading for specific endpoints
    const skipUrls = [
      '/api/notifications',
      '/api/health',
      '/api/ping'
    ];

    return skipUrls.some(url => req.url.includes(url));
  }
}

@Injectable()
export class ErrorInterceptor implements HttpInterceptor {
  private notificationService = inject(NotificationService);

  private router = inject(Router);

  intercept(req: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
    return next.handle(req).pipe(
      catchError((error: HttpErrorResponse) => {
        this.handleError(error);
        return throwError(() => error);
      })
    );
  }

  private handleError(error: HttpErrorResponse): void {
    let message = 'Ocorreu um erro inesperado';
    let title = 'Erro';

    switch (error.status) {
      case 400:
        title = 'Requisição Inválida';
        message = error.error?.message || 'Dados inválidos fornecidos';
        break;

      case 401:
        title = 'Não Autorizado';
        message = 'Sessão expirada. Por favor, faça login novamente.';
        this.handleUnauthorized();
        break;

      case 403:
        title = 'Acesso Negado';
        message = 'Você não tem permissão para realizar esta ação.';
        break;

      case 404:
        title = 'Não Encontrado';
        message = 'O recurso solicitado não foi encontrado.';
        break;

      case 409:
        title = 'Conflito';
        message = error.error?.message || 'Conflito com o estado atual do recurso.';
        break;

      case 422:
        title = 'Entidade Não Processável';
        message = error.error?.message || 'Os dados fornecidos não puderam ser processados.';
        break;

      case 429:
        title = 'Muitas Requisições';
        message = 'Você excedeu o limite de requisições. Por favor, aguarde.';
        break;

      case 500:
        title = 'Erro do Servidor';
        message = 'Ocorreu um erro no servidor. Por favor, tente novamente.';
        break;

      case 502:
      case 503:
      case 504:
        title = 'Serviço Indisponível';
        message = 'O serviço está temporariamente indisponível. Por favor, tente novamente.';
        break;

      default:
        if (error.status >= 400 && error.status < 500) {
          title = 'Erro de Cliente';
          message = error.error?.message || 'Ocorreu um erro na requisição.';
        } else if (error.status >= 500) {
          title = 'Erro do Servidor';
          message = 'Ocorreu um erro no servidor. Por favor, tente novamente.';
        }
        break;
    }

    this.notificationService.notifyError(title, message);
  }

  private handleUnauthorized(): void {
    // Limpar dados de autenticação
    // Limpar autenticação local
    localStorage.removeItem('token');
    localStorage.removeItem('user');

    // Redirecionar para login com mensagem
    this.router.navigate(['/login'], { 
      queryParams: { 
        message: 'Sessão expirada. Por favor, faça login novamente.' 
      } 
    });
  }
}

@Injectable()
export class TimeoutInterceptor implements HttpInterceptor {
  private readonly DEFAULT_TIMEOUT = 30000; // 30 segundos

  intercept(req: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
    const timeoutValue = req.headers.get('timeout') || this.DEFAULT_TIMEOUT;
    const timeoutMs = typeof timeoutValue === 'string' ? parseInt(timeoutValue, 10) : timeoutValue;

    return next.handle(req).pipe(
      timeout(timeoutMs),
      catchError(error => {
        if (error.name === 'TimeoutError') {
          const notificationService = inject(NotificationService);
          notificationService.notifyWarning('Tempo Limite Excedido', 'A requisição demorou muito tempo para responder.');
        }
        return throwError(() => error);
      })
    );
  }
}

@Injectable()
export class RetryInterceptor implements HttpInterceptor {
  private readonly MAX_RETRIES = 3;
  private readonly RETRY_DELAY = 1000; // 1 segundo

  intercept(req: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
    return this.handleRequest(req, next, 0);
  }

  private handleRequest(req: HttpRequest<any>, next: HttpHandler, retryCount: number): Observable<HttpEvent<any>> {
    return next.handle(req).pipe(
      catchError((error: HttpErrorResponse) => {
        if (this.shouldRetry(error, retryCount)) {
          return this.delay(this.RETRY_DELAY).pipe(
            switchMap(() => this.handleRequest(req, next, retryCount + 1))
          );
        }
        return throwError(() => error);
      })
    );
  }

  private shouldRetry(error: HttpErrorResponse, retryCount: number): boolean {
    // Não tentar novamente se já atingiu o limite
    if (retryCount >= this.MAX_RETRIES) {
      return false;
    }

    // Não tentar novamente para erros de cliente (4xx)
    if (error.status >= 400 && error.status < 500) {
      return false;
    }

    // Tentar novamente para erros de servidor (5xx) e erros de rede
    return error.status >= 500 || !error.status;
  }

  private delay(ms: number): Observable<void> {
    return new Observable<void>(observer => {
      setTimeout(() => {
        observer.next();
        observer.complete();
      }, ms);
    });
  }
}

