      <input
        matInput
        [type]="type"
        [placeholder]="placeholder"
        [disabled]="disabled"
        [readonly]="readonly"
        [(ngModel)]="value"
        (ngModelChange)="onChange($event)"
        (blur)="onTouched()"
        (focus)="onFocus()"
        [autocomplete]="autocomplete"
      />

      <!-- Ícone prefix -->
      <mat-icon *ngIf="prefixIcon" matPrefix>{{ prefixIcon }}</mat-icon>

      <!-- Ícone sufix -->
      <mat-icon *ngIf="suffixIcon" matSuffix>{{ suffixIcon }}</mat-icon>

      <!-- Botão clear -->
      <button
        *ngIf="showClear && value && !disabled"
        mat-icon-button
        matSuffix
        (click)="clear()"
        type="button"
        aria-label="Clear"
      >
        <mat-icon>close</mat-icon>
      </button>

      <!-- Botão de visibilidade para senhas -->
      <button
        *ngIf="type === 'password' && showPasswordToggle"
        mat-icon-button
        matSuffix
        (click)="togglePasswordVisibility()"
        type="button"
        [attr.aria-label]="showPassword ? 'Hide password' : 'Show password'"
      >
        <mat-icon>{{ showPassword ? 'visibility_off' : 'visibility' }}</mat-icon>
      </button>

      <!-- Hint -->
      <mat-hint *ngIf="hint && !hasError()">{{ hint }}</mat-hint>

      <!-- Erros de validação -->
      <mat-error *ngIf="hasError()">
        <mat-icon>error_outline</mat-icon>
        {{ getErrorMessage() }}
      </mat-error>

      <!-- Sucesso -->
      <mat-hint *ngIf="hasSuccess() && successMessage" class="success-message">
        <mat-icon>check_circle</mat-icon>
        {{ successMessage }}
      </mat-hint>
    </mat-form-field>
  `,
  styles: [`
    .app-input {
      width: 100%;
      margin-bottom: 0.5rem;
    }

    .app-input.error {
      --mdc-filled-text-field-error-active-indicator-color: #f44336;
    }

    .app-input.success {
      --mdc-filled-text-field-active-indicator-color: #4caf50;
    }

    mat-error, .success-message {
      display: flex;
      align-items: center;
      gap: 0.5rem;
      font-size: 0.875rem;
    }

    mat-error mat-icon, .success-message mat-icon {
      font-size: 1rem;
      width: 1rem;
      height: 1rem;
    }

    /* Estados de foco */
    .app-input:focus-within {
      transform: translateY(-1px);
      transition: transform 0.2s ease;
    }

    /* Tamanhos */
    :host(.small) .app-input {
      font-size: 0.875rem;
    }

    :host(.large) .app-input {
      font-size: 1.125rem;
    }

    /* Variante outline */
    :host(.outline) .app-input {
      --mdc-outlined-text-field-container-shape: 8px;
    }
  `]
})
export class InputComponent implements ControlValueAccessor {
  @Input() label = ''
  @Input() type: 'text' | 'email' | 'password' | 'number' | 'tel' | 'url' = 'text'
  @Input() placeholder = ''
  @Input() hint = ''
  @Input() prefixIcon = ''
  @Input() suffixIcon = ''
  @Input() showClear = false
  @Input() showPasswordToggle = false
  @Input() disabled = false
  @Input() readonly = false
  @Input() autocomplete = 'off'
  @Input() size: 'normal' | 'small' | 'large' = 'normal'
  @Input() variant: 'filled' | 'outline' = 'filled'
  @Input() validations: ValidationRule[] = []
  @Input() successMessage = ''
  @Input() validateOnBlur = true
  @Input() validateOnChange = false

  value = ''
  touched = false
  focused = false
  showPassword = false
  errors: string[] = []

  onChange = (value: string) => {}
  onTouched = () => {}

  writeValue(value: string): void {
    this.value = value
  }

  registerOnChange(fn: (value: string) => void): void {
    this.onChange = fn
  }

  registerOnTouched(fn: () => void): void {
    this.onTouched = fn
  }

  setDisabledState(isDisabled: boolean): void {
    this.disabled = isDisabled
  }

  onFocus(): void {
    this.focused = true
  }

  clear(): void {
    this.value = ''
    this.onChange('')
    this.validate()
  }

  togglePasswordVisibility(): void {
    this.showPassword = !this.showPassword
    this.type = this.showPassword ? 'text' : 'password'
  }

  validate(): void {
    this.errors = []

    for (const rule of this.validations) {
      const isValid = this.validateRule(rule)
      if (!isValid) {
        this.errors.push(rule.message)
      }
    }
  }

  private validateRule(rule: ValidationRule): boolean {
    switch (rule.type) {
      case 'required':
        return this.value.trim().length > 0
      case 'email':
        return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(this.value)
      case 'minLength':
        return this.value.length >= (rule.value || 0)
      case 'maxLength':
        return this.value.length <= (rule.value || Infinity)
      case 'pattern':
        return new RegExp(rule.value).test(this.value)
      default:
        return true
    }
  }

  hasError(): boolean {
    return this.errors.length > 0
  }

 get showSuccess(): boolean {
    return !this.hasError() && this.touched && !!this.successMessage
  }

  hasSuccess(): boolean {
    return this.showSuccess
  }

  getErrorMessage(): string {
    return this.errors[0] || ''
  }
}

import { ComponentFixture, TestBed } from '@angular/core/testing'
import { LoadingComponent } from './loading.component'
import { LoadingStateService } from '../../../core/services/loading-state.service'
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner'
import { of } from 'rxjs'

class MockLoadingStateService {
  private loadingStates = new Map<string, any>()

  isKeyLoading(key: string): boolean {
    return this.loadingStates.has(key) && this.loadingStates.get(key).isLoading
  }

  getLoadingState(key: string): any {
    return this.loadingStates.get(key)
  }

  startLoading(key: string, config?: any): void {
    this.loadingStates.set(key, { isLoading: true, ...config })
  }

  stopLoading(key: string): void {
    if (this.loadingStates.has(key)) {
      this.loadingStates.get(key).isLoading = false
    }
  }
}

describe('LoadingComponent', () => {
  let component: LoadingComponent
  let fixture: ComponentFixture<LoadingComponent>
  let loadingStateService: MockLoadingStateService

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [LoadingComponent, MatProgressSpinnerModule],
      providers: [
        { provide: LoadingStateService, useClass: MockLoadingStateService }
      ]
    }).compileComponents()

    fixture = TestBed.createComponent(LoadingComponent)
    component = fixture.componentInstance
    loadingStateService = TestBed.inject(LoadingStateService) as any
    fixture.detectChanges()
  })

  it('should create', () => {
    expect(component).toBeTruthy()
  })

  describe('default values', () => {
    it('should have default isLoading as false', () => {
      expect(component.isLoading).toBe(false)
    })

    it('should have default message as empty string', () => {
      expect(component.message).toBe('')
    })

    it('should have default diameter as 40', () => {
      expect(component.diameter).toBe(40)
    })

    it('should have default color as primary', () => {
      expect(component.color).toBe('primary')
    })

    it('should have default mode as indeterminate', () => {
      expect(component.mode).toBe('indeterminate')
    })

    it('should have default overlay as false', () => {
      expect(component.overlay).toBe(false)
    })

    it('should have default showSpinner as true', () => {
      expect(component.showSpinner).toBe(true)
    })

    it('should have default showMessage as true', () => {
      expect(component.showMessage).toBe(true)
    })
  })

  describe('actualLoading', () => {
    it('should return isLoading when loadingKey is not provided', () => {
      component.isLoading = true
      expect(component.actualLoading).toBe(true)

      component.isLoading = false
      expect(component.actualLoading).toBe(false)
    })

    it('should return loading state from service when loadingKey is provided', () => {
      component.loadingKey = 'test-key'
      component.isLoading = false

      loadingStateService.startLoading('test-key')
      expect(component.actualLoading).toBe(true)

      loadingStateService.stopLoading('test-key')
      expect(component.actualLoading).toBe(false)
    })
  })

  describe('actualMessage', () => {
    it('should return message when loadingKey is not provided', () => {
      component.message = 'Test message'
      expect(component.actualMessage).toBe('Test message')
    })

    it('should return message from service when loadingKey is provided', () => {
      component.loadingKey = 'test-key'
      component.message = 'Default message'

      loadingStateService.startLoading('test-key', { message: 'Service message' })
      expect(component.actualMessage).toBe('Service message')

      loadingStateService.stopLoading('test-key')
      expect(component.actualMessage).toBe('Default message') // Falls back to component message
    })
  })

  describe('template rendering', () => {
    it('should show loading container when actualLoading is true', () => {
      component.isLoading = true
      fixture.detectChanges()

      const loadingContainer = fixture.nativeElement.querySelector('.loading-container')
      expect(loadingContainer).toBeTruthy()
    })

    it('should hide loading container when actualLoading is false', () => {
      component.isLoading = false
      fixture.detectChanges()

      const loadingContainer = fixture.nativeElement.querySelector('.loading-container')
      expect(loadingContainer).toBeFalsy()
    })

    it('should show spinner when showSpinner is true', () => {
      component.isLoading = true
      component.showSpinner = true
      fixture.detectChanges()

      const spinner = fixture.nativeElement.querySelector('mat-spinner')
      expect(spinner).toBeTruthy()
    })

    it('should hide spinner when showSpinner is false', () => {
      component.isLoading = true
      component.showSpinner = false
      fixture.detectChanges()

      const spinner = fixture.nativeElement.querySelector('mat-spinner')
      expect(spinner).toBeFalsy()
    })

    it('should show message when showMessage and actualMessage are truthy', () => {
      component.isLoading = true
      component.showMessage = true
      component.message = 'Loading message'
      fixture.detectChanges()

      const messageElement = fixture.nativeElement.querySelector('.loading-message')
      expect(messageElement).toBeTruthy()
      expect(messageElement.textContent).toContain('Loading message')
    })

    it('should hide message when showMessage is false', () => {
      component.isLoading = true
      component.showMessage = false
      component.message = 'Loading message'
      fixture.detectChanges()

      const messageElement = fixture.nativeElement.querySelector('.loading-message')
      expect(messageElement).toBeFalsy()
    })

    it('should apply overlay class when overlay is true', () => {
      component.isLoading = true
      component.overlay = true
      fixture.detectChanges()

      const loadingContainer = fixture.nativeElement.querySelector('.loading-container')
      expect(loadingContainer).toHaveClass('overlay')
    })

    it('should render ng-content when not loading', () => {
      component.isLoading = false
      fixture.detectChanges()

      const ngContent = fixture.nativeElement.querySelector('ng-content')
      expect(ngContent).toBeTruthy()
    })
  })
})

import { Component, Input, Output, EventEmitter, ChangeDetectionStrategy, inject } from '@angular/core'
import { CommonModule } from '@angular/common'
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner'
import { LoadingStateService } from '../../../core/services/loading-state.service'

/**
 * Componente de loading reutilizável para todo o sistema
 * Uso: <app-loading [isLoading]="true" [message]="Carregando..." />
 */
@Component({
  selector: 'app-loading',
  standalone: true,
  imports: [CommonModule, MatProgressSpinnerModule],
  template: `
    <div *ngIf="actualLoading" class="loading-container" [class.overlay]="overlay">
      <div class="loading-content">
        <mat-spinner 
          *ngIf="showSpinner"
          [diameter]="diameter" 
          [color]="color"
          [mode]="mode">
        </mat-spinner>
        <p *ngIf="showMessage && actualMessage" class="loading-message">{{ actualMessage }}</p>
        <p *ngIf="subMessage" class="loading-submessage">{{ subMessage }}</p>
      </div>
    </div>
    <ng-content *ngIf="!actualLoading"></ng-content>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  styles: [`
    .loading-container {
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 2rem;
      min-height: 200px;
    }

    .loading-container.overlay {
      position: absolute;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background-color: rgba(255, 255, 255, 0.9);
      z-index: 1000;
      padding: 0;
    }

    .loading-content {
      text-align: center;
    }

    .loading-message {
      margin: 1rem 0 0.5rem 0;
      font-size: 1.1rem;
      font-weight: 500;
      color: #333;
    }

    .loading-submessage {
      margin: 0;
      font-size: 0.9rem;
      color: #666;
    }

    /* Animação suave de entrada/saída */
    :host {
      display: block;
      transition: opacity 0.3s ease;
    }
  `]
})
export class LoadingComponent {
  private readonly loadingStateService = inject(LoadingStateService)

  @Input() isLoading = false
  @Input() message = ''
  @Input() subMessage = ''
  @Input() diameter = 40
  @Input() color: 'primary' | 'accent' | 'warn' = 'primary'
  @Input() mode: 'determinate' | 'indeterminate' = 'indeterminate'
  @Input() overlay = false
  @Input() loadingKey?: string
  @Input() showSpinner = true
  @Input() showMessage = true

  get actualLoading(): boolean {
    if (this.loadingKey) {
      return this.loadingStateService.isKeyLoading(this.loadingKey)
    }
    return this.isLoading
  }

  get actualMessage(): string {
    if (this.loadingKey) {
      const state = this.loadingStateService.getLoadingState(this.loadingKey)
      return state?.message || this.message
    }
    return this.message
  }
}

import { Component, Input, Output, EventEmitter, OnInit, OnDestroy } from '@angular/core'
import { CommonModule } from '@angular/common'
import { MatDialogModule, MatDialogRef } from '@angular/material/dialog'
import { MatButtonModule } from '@angular/material/button'
import { MatIconModule } from '@angular/material/icon'
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner'

export interface ModalAction {
  label: string
  action: () => void | Promise<void>
  type?: 'primary' | 'secondary' | 'danger'
  disabled?: boolean
  loading?: boolean
}

export interface ModalConfig {
  title: string
  size?: 'small' | 'medium' | 'large' | 'full'
  closable?: boolean
  backdrop?: boolean
  centered?: boolean
  scrollable?: boolean
}

@Component({
  selector: 'app-modal',
  standalone: true,
  imports: [
    CommonModule,
    MatDialogModule,
    MatButtonModule,
    MatIconModule,
    MatProgressSpinnerModule
  ],
  template: `
    <div class="modal-overlay" *ngIf="isOpen" (click)="onBackdropClick($event)">
      <div class="modal-container" [class]="getModalClasses()" (click)="$event.stopPropagation()">
        <!-- Header -->
        <div class="modal-header" *ngIf="config.title">
          <h2 class="modal-title">{{ config.title }}</h2>
          <button 
            *ngIf="config.closable !== false" 
            class="modal-close" 
            (click)="close()"
            aria-label="Close modal">
            <mat-icon>close</mat-icon>
          </button>
        </div>

        <!-- Content -->
        <div class="modal-body" [class.scrollable]="config.scrollable">
          <ng-content></ng-content>
        </div>

        <!-- Footer with actions -->
        <div class="modal-footer" *ngIf="actions && actions.length > 0">
          <div class="modal-actions">
            <button
              *ngFor="let action of actions; let i = index"
              mat-button
              [class]="getActionButtonClasses(action)"
              [disabled]="action.disabled || action.loading"
              (click)="handleAction(action)"
              [attr.data-testid]="'modal-action-' + i">
              <span *ngIf="!action.loading">{{ action.label }}</span>
              <mat-spinner *ngIf="action.loading" diameter="20"></mat-spinner>
            </button>
          </div>
        </div>
      </div>
    </div>
  `,
  styles: [`
    .modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background-color: rgba(0, 0, 0, 0.5);
      display: flex;
      align-items: center;
      justify-content: center;
      z-index: 1000;
      animation: fadeIn 0.2s ease-out;
    }

    .modal-container {
      background: white;
      border-radius: 8px;
      box-shadow: 0 11px 15px -7px rgba(0, 0, 0, 0.2), 
                  0 24px 38px 3px rgba(0, 0, 0, 0.14), 
                  0 9px 46px 8px rgba(0, 0, 0, 0.12);
      max-height: 90vh;
      max-width: 90vw;
      display: flex;
      flex-direction: column;
      animation: slideIn 0.3s ease-out;
    }

    .modal-container.small {
      width: 400px;
    }

    .modal-container.medium {
      width: 600px;
    }

    .modal-container.large {
      width: 800px;
    }

    .modal-container.full {
      width: 95vw;
      height: 95vh;
    }

    .modal-container.centered {
      margin: auto;
    }

    .modal-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 20px 24px;
      border-bottom: 1px solid #e0e0e0;
    }

    .modal-title {
      margin: 0;
      font-size: 1.25rem;
      font-weight: 500;
      color: rgba(0, 0, 0, 0.87);
    }

    .modal-close {
      background: none;
      border: none;
      padding: 8px;
      cursor: pointer;
      border-radius: 50%;
      display: flex;
      align-items: center;
      justify-content: center;
      transition: background-color 0.2s;
    }

    .modal-close:hover {
      background-color: rgba(0, 0, 0, 0.04);
    }

    .modal-body {
      flex: 1;
      padding: 24px;
      overflow-y: auto;
    }

    .modal-body.scrollable {
      max-height: 60vh;
    }

    .modal-footer {
      padding: 16px 24px;
      border-top: 1px solid #e0e0e0;
      display: flex;
      justify-content: flex-end;
    }

    .modal-actions {
      display: flex;
      gap: 8px;
    }

    .modal-actions button {
      min-width: 88px;
    }

    .action-primary {
      background-color: #1976d2;
      color: white;
    }

    .action-secondary {
      background-color: transparent;
      color: #1976d2;
      border: 1px solid #1976d2;
    }

    .action-danger {
      background-color: #f44336;
      color: white;
    }

    .action-primary:hover:not(:disabled) {
      background-color: #1565c0;
    }

    .action-secondary:hover:not(:disabled) {
      background-color: rgba(25, 118, 210, 0.04);
    }

    .action-danger:hover:not(:disabled) {
      background-color: #d32f2f;
    }

    button:disabled {
      opacity: 0.6;
      cursor: not-allowed;
    }

    @keyframes fadeIn {
      from {
        opacity: 0;
      }
      to {
        opacity: 1;
      }
    }

    @keyframes slideIn {
      from {
        transform: translateY(-20px);
        opacity: 0;
      }
      to {
        transform: translateY(0);
        opacity: 1;
      }
    }

    @media (max-width: 768px) {
      .modal-container {
        width: 95vw !important;
        margin: 16px;
      }

      .modal-header,
      .modal-body,
      .modal-footer {
        padding-left: 16px;
        padding-right: 16px;
      }
    }
  `]
})
export class ModalComponent implements OnInit, OnDestroy {
  @Input() isOpen = false
  @Input() config: ModalConfig = {
    title: '',
    size: 'medium',
    closable: true,
    backdrop: true,
    centered: true,
    scrollable: false
  }
  @Input() actions: ModalAction[] = []

  @Output() closed = new EventEmitter<void>()
  @Output() actionExecuted = new EventEmitter<ModalAction>()

  private dialogRef?: MatDialogRef<any>

  ngOnInit() {
    if (this.isOpen) {
      this.preventBodyScroll()
    }
  }

  ngOnDestroy() {
    this.restoreBodyScroll()
  }

  private preventBodyScroll() {
    document.body.style.overflow = 'hidden'
  }

  private restoreBodyScroll() {
    document.body.style.overflow = ''
  }

  close(): void {
    this.isOpen = false
    this.closed.emit()
    this.restoreBodyScroll()
  }

  onBackdropClick(event: MouseEvent): void {
    if (this.config.backdrop !== false) {
      this.close()
    }
  }

  getModalClasses(): string {
    const classes = ['modal-container']
    if (this.config.size) {
      classes.push(this.config.size)
    }
    if (this.config.centered) {
      classes.push('centered')
    }
    return classes.join(' ')
  }

  getActionButtonClasses(action: ModalAction): string {
    const type = action.type || 'secondary'
    return `action-${type}`
  }

  async handleAction(action: ModalAction): Promise<void> {
    if (action.disabled || action.loading) {
      return
    }

    action.loading = true
    try {
      await action.action()
      this.actionExecuted.emit(action)
    } catch (error) {
      console.error('Error executing modal action:', error)
    } finally {
      action.loading = false
    }
  }
}
